  const upperCaseStr = string.toUpperCase();

  for (let i = 0; i < upperCaseStr.length; i++) {
    const currentChar = upperCaseStr.charAt(i);

    if (!charMap.has(currentChar)) {
      charCount += 1;
      charMap.set(currentChar, 1);
    }
  }

